JS_CODE = "// ──────────────────────────────────\n// Constants\n// ──────────────────────────────────\nconst STORAGE_KEY = 'kidsgrowth-v1';\n\nconst MILESTONES = [\n  { id:'m1', name:'首すわり', target:'3〜4ヶ月', cat:'運動発達', icon:'👶' },\n  { id:'m2', name:'寝返り', target:'4〜6ヶ月', cat:'運動発達', icon:'🔄' },\n  { id:'m3', name:'お座り', target:'6〜8ヶ月', cat:'運動発達', icon:'🧸' },\n  { id:'m4', name:'ハイハイ', target:'7〜10ヶ月', cat:'運動発達', icon:'🏃' },\n  { id:'m5', name:'つかまり立ち', target:'8〜11ヶ月', cat:'運動発達', icon:'🦺' },\n  { id:'m6', name:'ひとり立ち', target:'10〜14ヶ月', cat:'運動発達', icon:'⭐' },\n  { id:'m7', name:'ひとり歩き', target:'11〜15ヶ月', cat:'運動発達', icon:'👟' },\n  { id:'m8', name:'喃語（バブバブ）', target:'2〜6ヶ月', cat:'言語発達', icon:'💬' },\n  { id:'m9', name:'意味のある言葉', target:'12〜18ヶ月', cat:'言語発達', icon:'🗣️' },\n  { id:'m10', name:'2語文', target:'18〜24ヶ月', cat:'言語発達', icon:'📢' },\n  { id:'m11', name:'社会的微笑み', target:'1〜3ヶ月', cat:'社会性', icon:'😊' },\n  { id:'m12', name:'後追い', target:'6〜9ヶ月', cat:'社会性', icon:'🐾' },\n  { id:'m13', name:'人見知り', target:'6〜12ヶ月', cat:'社会性', icon:'🙈' },\n];\n\nconst VACCINES = [\n  { id:'vax1', name:'ヒブ（Hib）感染症', timing:'2・3・4ヶ月、12〜15ヶ月', type:'定期' },\n  { id:'vax2', name:'小児用肺炎球菌', timing:'2・3・4ヶ月、12〜15ヶ月', type:'定期' },\n  { id:'vax3', name:'B型肝炎', timing:'2・3・7〜8ヶ月', type:'定期' },\n  { id:'vax4', name:'ロタウイルス', timing:'2・3（・4）ヶ月', type:'定期' },\n  { id:'vax5', name:'四種混合（DPT-IPV）', timing:'3・4・5ヶ月、18ヶ月', type:'定期' },\n  { id:'vax6', name:'BCG（結核）', timing:'5〜8ヶ月', type:'定期' },\n  { id:'vax7', name:'MR（麻疹・風疹）', timing:'1歳・就学前', type:'定期' },\n  { id:'vax8', name:'水痘（みずぼうそう）', timing:'1歳・1.5歳', type:'定期' },\n  { id:'vax9', name:'日本脳炎', timing:'3歳・4歳・9歳', type:'定期' },\n  { id:'vax10', name:'おたふくかぜ', timing:'1歳・就学前', type:'任意' },\n  { id:'vax11', name:'インフルエンザ', timing:'毎年秋（6ヶ月〜）', type:'任意' },\n];\n\nconst FAQS = [\n  ['身長や体重の記録はどこに保存されますか？', 'すべてのデータはお使いのブラウザのLocalStorageに保存されます。サーバーには一切送信されず、プライバシーが完全に保護されます。'],\n  ['複数の子どもを登録できますか？', 'はい、何人でも登録できます。画面上部のヘッダーからいつでも切り替え可能です。'],\n  ['発達マイルストーンとは何ですか？', '赤ちゃん・幼児の発達の節目となる動作・能力のことです。首すわり・寝返りなど運動発達、言語発達、社会性の発達など13項目を管理できます。'],\n  ['データをバックアップする方法はありますか？', 'データはLocalStorageに保存されます。定期的にスクリーンショットを撮るか、母子手帳と併用して記録を残すことをお勧めします。'],\n  ['成長グラフはどのように使いますか？', '「成長記録」タブ内に自動的にグラフが表示されます。身長・体重それぞれのボタンで切り替えられます。2件以上のデータを登録すると推移グラフが表示されます。'],\n  ['予防接種の管理はどのようにすればいいですか？', '「予防接種」タブで各ワクチンの接種日を入力すると、完了マークが付きます。母子手帳と照らし合わせながら記録しましょう。'],\n  ['スマートフォンでも使えますか？', 'はい、モバイル対応しています。ブラウザの「ホーム画面に追加」機能でアプリのように使うこともできます。'],\n];\n\n// ──────────────────────────────────\n// State\n// ──────────────────────────────────\nlet state = { children: [], activeId: null };\nlet chartType = 'height';\nlet pendingMsId = null;\nlet selEmoji = '';\n\n// ──────────────────────────────────\n// Storage\n// ──────────────────────────────────\nfunction loadState() {\n  try {\n    const raw = localStorage.getItem(STORAGE_KEY);\n    if (raw) state = JSON.parse(raw);\n  } catch(e) {\n    console.warn('[KidsGrowth] load error', e);\n    localStorage.removeItem(STORAGE_KEY);\n  }\n}\n\nfunction saveState() {\n  try {\n    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));\n  } catch(e) {\n    toast('err', 'データの保存に失敗しました');\n    console.error('[KidsGrowth] save error', e);\n  }\n}\n\nfunction activeChild() {\n  return state.children.find(c => c.id === state.activeId) || null;\n}\n\n// ──────────────────────────────────\n// Child management\n// ──────────────────────────────────\nfunction addChild() {\n  const name = document.getElementById('input-child-name').value.trim();\n  const birth = document.getElementById('input-child-birth').value;\n  const gender = document.getElementById('input-child-gender').value;\n\n  if (!name) { toast('err', 'お名前を入力してください'); return; }\n  if (!birth) { toast('err', '生年月日を入力してください'); return; }\n\n  try {\n    const child = { id: Date.now().toString(), name, birth, gender, records: [], milestones: {}, vaccines: {}, memories: [] };\n    state.children.push(child);\n    state.activeId = child.id;\n    saveState();\n    closeModal('modal-add-child');\n    document.getElementById('input-child-name').value = '';\n    document"
